import { WatchedQuery } from '@powersync/common';
/**
 * A hook to access and subscribe to the results of an existing {@link WatchedQuery}.
 * @example
 * export const ContentComponent = () => {
 * const { data: lists }  = useWatchedQuerySuspenseSubscription(listsQuery);
 *
 * return <View>
 *   {lists.map((l) => (
 *     <Text key={l.id}>{JSON.stringify(l)}</Text>
 *   ))}
 * </View>;
 * }
 *
 * export const DisplayComponent = () => {
 * return (
 *    <Suspense fallback={<div>Loading content...</div>}>
 *       <ContentComponent />
 *    </Suspense>
 * );
 * }
 */
export declare const useWatchedQuerySuspenseSubscription: <ResultType = unknown, Query extends WatchedQuery<ResultType> = WatchedQuery<ResultType>>(query: Query) => Query["state"];
